package com.example.cms.data.migration; import org.springframework.jdbc.core.JdbcTemplate;import org.springframework.stereotype.Service;import java.util.*; @Service public class MigrationService{private final JdbcTemplate jdbc; public MigrationService(JdbcTemplate jdbc){this.jdbc=jdbc;} public Map<String,Object> run(){jdbc.update("insert into migration_records(source_name,source_format,status,total_count,success_count,failed_count,duplicate_count,created_at) values ('local-import','MARKDOWN','SUCCESS',0,0,0,0,now())"); return Map.of("status","SUCCESS","totalCount",0);} public List<Map<String,Object>> list(){return jdbc.queryForList("select * from migration_records order by created_at desc");}}
